"use strict";(globalThis.webpackChunkgsf_docusaurus_template=globalThis.webpackChunkgsf_docusaurus_template||[]).push([[9935],{4523(e){e.exports=JSON.parse('{"tag":{"label":"persona:data-engineer","permalink":"/gsf-patterns/tags/persona-data-engineer","allTagsPath":"/gsf-patterns/tags","count":5,"items":[{"id":"development/data-handling/compress-stored-data","title":"Compress stored data","description":"Storing uncompressed data wastes bandwidth and increases storage capacity requirements; applying appropriate compression reduces both storage consumption and the energy needed to read and write it.","permalink":"/gsf-patterns/development/data-handling/compress-stored-data"},{"id":"development/pre-trained-transfer-learning","title":"Leverage pre-trained models and transfer learning","description":"Fine-tune existing pre-trained models instead of training from scratch to dramatically reduce the compute, energy, and time required for model development.","permalink":"/gsf-patterns/development/pre-trained-transfer-learning"},{"id":"operations/resource-lifecycle/optimise-storage-resource-utilisation","title":"Optimise storage utilization","description":"It\'s better to maximise storage utilisation so the storage layer is optimised for the task, not only in terms of energy proportionality but also in terms of embodied carbon. Two storage units running at low utilization rates will consume more energy than one running at a high utilization rate. In addition, the unused capacity on the underutilised storage unit could be more efficiently used for another task or process.","permalink":"/gsf-patterns/operations/resource-lifecycle/optimise-storage-resource-utilisation"},{"id":"development/data-handling/optimize-data-storage-ai-training","title":"Optimize data storage formats for AI training and inference","description":"Use efficient storage formats, compression, and indexing strategies for AI datasets and embeddings to reduce storage footprint, data transfer, and retrieval compute.","permalink":"/gsf-patterns/development/data-handling/optimize-data-storage-ai-training"},{"id":"operations/resource-lifecycle/set-retention-policy-on-storage-resources","title":"Set storage retention policies","description":"From an embodied carbon perspective, it\'s better to have an automated mechanism to delete unused storage resources so we are efficient with hardware and so that the storage layer is optimised for the task.","permalink":"/gsf-patterns/operations/resource-lifecycle/set-retention-policy-on-storage-resources"}],"unlisted":false}}')}}]);